<?php
declare(strict_types=1);
if(PHP_SAPI!=='cli'){http_response_code(404);exit('Not found.');}
require_once dirname(__DIR__).'/api/intelligence/_intelligence.php';$pdo=mg_db();$root=dirname(__DIR__).'/storage/private/intelligence';if(!is_dir($root)&&!mkdir($root,0700,true)&&!is_dir($root))throw new RuntimeException('Unable to create export directory.');$jobs=$pdo->query("SELECT * FROM intelligence_export_jobs WHERE status='queued' ORDER BY created_at LIMIT 20")->fetchAll();foreach($jobs as $job){$pdo->prepare("UPDATE intelligence_export_jobs SET status='processing',updated_at=NOW() WHERE id=?")->execute([(int)$job['id']]);try{$sql='SELECT metric_date,source_type,SUM(items_issued) items_issued,SUM(issued_value_cents) issued_value_cents,SUM(impressions) impressions,SUM(opens) opens,SUM(claims) claims,SUM(redemptions) redemptions,SUM(unique_recipients) unique_recipients FROM demand_fact_daily WHERE merchant_user_id=? AND metric_date BETWEEN ? AND ? GROUP BY metric_date,source_type ORDER BY metric_date,source_type';$stmt=$pdo->prepare($sql);$stmt->execute([(int)$job['merchant_user_id'],$job['date_from'],$job['date_to']]);$rows=$stmt->fetchAll(PDO::FETCH_ASSOC);if($job['privacy_mode']==='k_anonymous')$rows=array_values(array_filter($rows,static fn(array $row):bool=>(int)$row['unique_recipients']>=(int)$job['minimum_cohort_size']));$ext=$job['format']==='json'?'json':'csv';$key='intelligence/'.date('Y/m').'/'.$job['public_id'].'.'.$ext;$path=dirname(__DIR__).'/storage/private/'.$key;if(!is_dir(dirname($path)))mkdir(dirname($path),0700,true);if($ext==='json')file_put_contents($path,json_encode($rows,JSON_PRETTY_PRINT|JSON_UNESCAPED_SLASHES));else{$handle=fopen($path,'wb');if($rows){fputcsv($handle,array_keys($rows[0]));foreach($rows as $row)fputcsv($handle,$row);}fclose($handle);}$checksum=hash_file('sha256',$path);$pdo->prepare("UPDATE intelligence_export_jobs SET status='ready',storage_provider='private_local',storage_key=?,checksum_sha256=?,row_count=?,expires_at=DATE_ADD(NOW(),INTERVAL 7 DAY),updated_at=NOW() WHERE id=?")->execute([$key,$checksum,count($rows),(int)$job['id']]);}catch(Throwable $e){$pdo->prepare("UPDATE intelligence_export_jobs SET status='failed',failure_message=?,updated_at=NOW() WHERE id=?")->execute([substr($e->getMessage(),0,500),(int)$job['id']]);}}echo "Processed ".count($jobs)." intelligence exports.\n";
